                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onTextDelta(
                     delta: try FfiConverterString.lift(delta)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        onToolCall: { (
            uniffiHandle: UInt64,
            name: RustBuffer,
